using System.Collections;
using System.Collections.Generic;
using System.IO;
using UnityEngine;


using System;using System.Collections.Generic;using System.IO;using UnityEngine;public class SaveManager : Singleton<SaveManager>{    private string _savePath;    public PlayerSaveData CurrentData;    // 기획자가 에디터에서 수치를 밸런싱할 정적 템플릿 참조    [SerializeField] private UpgradeStatsSO upgradeStatsTemplate;    private const int MaxHistoryEntries = 10;    protected override void Awake()    {        base.Awake();        // 모바일 환경의 영구 보존 경로 할당        _savePath = Path.Combine(Application.persistentDataPath, "neonflux_user_data.json");        LoadData();    }    public int HighScore => CurrentData != null ? CurrentData.highScore : 0;    public IReadOnlyList<PlayerSaveData.LeaderboardEntry> Leaderboard    {        get        {            if (CurrentData == null || CurrentData.scoreHistory == null) return new List<PlayerSaveData.LeaderboardEntry>();            var copy = new List<PlayerSaveData.LeaderboardEntry>(CurrentData.scoreHistory);            copy.Sort((a, b) => b.score.CompareTo(a.score));            return copy.AsReadOnly();        }    }    public void SaveData()    {        // 런타임 메모리에 존재하는 객체를 JSON 포맷의 문자열로 직렬화         string json = JsonUtility.ToJson(CurrentData);        File.WriteAllText(_savePath, json);    }    public void LoadData()    {        if (File.Exists(_savePath))        {            string json = File.ReadAllText(_savePath);            // 디스크에서 읽어온 문자열을 다시 객체로 역직렬화             CurrentData = JsonUtility.FromJson<PlayerSaveData>(json);            if (CurrentData.scoreHistory == null) CurrentData.scoreHistory = new List<PlayerSaveData.LeaderboardEntry>();        }        else        {            // 신규 유저 초기값 세팅            CurrentData = new PlayerSaveData            {                currentCoins = 0,                currentSpeedLevel = 1,                currentDriftLevel = 1,                currentStageLevel = 1            };        }    }    public void UpdateHighScore(int score)    {        if (CurrentData == null) return;        if (score > CurrentData.highScore)        {            CurrentData.highScore = score;        }    }    public void RecordGameScore(int score, string reason)    {        if (CurrentData == null) LoadData();        UpdateHighScore(score);        var entry = new PlayerSaveData.LeaderboardEntry(score, CurrentData.currentStageLevel, DateTime.UtcNow.ToString("s"), reason ?? string.Empty);        if (CurrentData.scoreHistory == null) CurrentData.scoreHistory = new List<PlayerSaveData.LeaderboardEntry>();        CurrentData.scoreHistory.Add(entry);        // 오래된 것부터 제거하여 최대 보관 수 유지        while (CurrentData.scoreHistory.Count > MaxHistoryEntries)        {            CurrentData.scoreHistory.RemoveAt(0);        }        SaveData();    }    public void ClearHistory()    {        if (CurrentData == null) return;        CurrentData.scoreHistory = new List<PlayerSaveData.LeaderboardEntry>();        SaveData();    }    /// <summary>    /// PlayerController가 현재 차량의 실제 속도 수치를 요청할 때 호출    /// JSON의 레벨 데이터와 SO의 스탯 데이터를 융합하여 반환     /// </summary>    public float GetCurrentMaxSpeed()    {        return upgradeStatsTemplate != null ? upgradeStatsTemplate.speedValuesByLevel : 0f;    }}